// Abstraction: Define abstract Player class and Scorer interface
abstract class Player {
    // Encapsulation: private data with protected access for subclasses
    private String name;
    private int jerseyNumber;
    protected int matchesPlayed;

    public Player(String name, int jerseyNumber) {
        this.name = name;
        this.jerseyNumber = jerseyNumber;
        this.matchesPlayed = 0;
    }

    // Encapsulation: getter/setter with validation
    public String getName() {
        return name;
    }

    public void setName(String name) {
        if (name != null && !name.isEmpty()) {
            this.name = name;
        }
    }

    // Abstraction: abstract method that subclasses must implement
    abstract void performRole();

    // Concrete method inherited by all subclasses
    public void recordMatch() {
        matchesPlayed++;
    }
}

// Scoring interface: defines a contract for scorers
interface Scorer {
    void scoreRuns(int runs);
    int getTotalRuns();
}

// Inheritance + Polymorphism + Encapsulation + Abstraction
class Batsman extends Player implements Scorer {
    private int totalRuns;
    private int inningsCount;
    private double strikeRate;

    public Batsman(String name, int jerseyNumber) {
        super(name, jerseyNumber);
        this.totalRuns = 0;
        this.inningsCount = 0;
    }

    // Polymorphism: override abstract method from Player
    @Override
    void performRole() {
        System.out.println(getName() + " is batting at the crease.");
    }

    // Implement Scorer interface
    @Override
    public void scoreRuns(int runs) {
        if (runs >= 0) {
            totalRuns += runs;
        }
    }

    @Override
    public int getTotalRuns() {
        return totalRuns;
    }

    // Encapsulation: controlled access to strikeRate
    public void setStrikeRate(int ballsFaced) {
        if (ballsFaced > 0) {
            this.strikeRate = (double) totalRuns / ballsFaced * 100;
        }
    }

    public double getStrikeRate() {
        return strikeRate;
    }
}

// Another subclass: Bowler
class Bowler extends Player {
    private int wicketsTaken;
    private double economy;
    private int ballsBowled;

    public Bowler(String name, int jerseyNumber) {
        super(name, jerseyNumber);
        this.wicketsTaken = 0;
        this.ballsBowled = 0;
    }

    // Polymorphism: override abstract method from Player
    @Override
    void performRole() {
        System.out.println(getName() + " is bowling from the crease.");
    }

    // Encapsulation: setters with validation
    public void addWicket(int runs, int balls) {
        if (runs >= 0 && balls > 0) {
            wicketsTaken++;
            ballsBowled += balls;
            this.economy = (double) runs / (ballsBowled / 6.0);
        }
    }

    public int getWicketsTaken() {
        return wicketsTaken;
    }

    public double getEconomy() {
        return economy;
    }
}

// AllRounder: demonstrates inheritance from Player and interface implementation
class AllRounder extends Player implements Scorer {
    private int totalRuns;
    private int wicketsTaken;

    public AllRounder(String name, int jerseyNumber) {
        super(name, jerseyNumber);
        this.totalRuns = 0;
        this.wicketsTaken = 0;
    }

    @Override
    void performRole() {
        System.out.println(getName() + " is batting or bowling as needed.");
    }

    @Override
    public void scoreRuns(int runs) {
        if (runs >= 0) {
            totalRuns += runs;
        }
    }

    @Override
    public int getTotalRuns() {
        return totalRuns;
    }

    public void addWicket() {
        wicketsTaken++;
    }

    public int getWicketsTaken() {
        return wicketsTaken;
    }
}

// Main class: demonstrates polymorphism in action
public class CricketMatch {
    public static void main(String[] args) {
        // Create players: Inheritance + Encapsulation
        Batsman rohit = new Batsman("Rohit Sharma", 45);
        Bowler bumrah = new Bowler("Jasprit Bumrah", 93);
        AllRounder hardik = new AllRounder("Hardik Pandya", 31);

        // Polymorphism: treat all as Player despite different types
        Player[] players = {rohit, bumrah, hardik};

        // Call performRole() on each: polymorphism ensures right behavior
        System.out.println("=== Match Start ===");
        for (Player player : players) {
            player.performRole();  // Polymorphism: runtime decision
            player.recordMatch();  // Inherited method
        }

        // Encapsulation: interact through public interface
        System.out.println("\n=== Batting Stats ===");
        rohit.scoreRuns(45);
        rohit.setStrikeRate(60);  // 45 runs off 60 balls = 75% strike rate
        System.out.println(rohit.getName() + ": " + rohit.getTotalRuns() + 
                           " runs, " + rohit.getStrikeRate() + "% SR");

        // AllRounder implements Scorer interface
        hardik.scoreRuns(28);
        hardik.addWicket();
        System.out.println(hardik.getName() + ": " + hardik.getTotalRuns() + 
                           " runs, " + hardik.getWicketsTaken() + " wicket(s)");

        // Bowler encapsulation example
        System.out.println("\n=== Bowling Stats ===");
        bumrah.addWicket(32, 24);  // 32 runs, 24 balls = 8.0 economy
        System.out.println(bumrah.getName() + ": " + bumrah.getWicketsTaken() + 
                           " wickets, " + bumrah.getEconomy() + " economy");

        // Polymorphic method: works with any Scorer
        System.out.println("\n=== Scorers in Match ===");
        Scorer[] scorers = {rohit, hardik};
        for (Scorer scorer : scorers) {
            System.out.println("Total runs: " + scorer.getTotalRuns());
        }
    }
}

